}

package org.apache.commons.compress.archivers.cpio.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.compress.archivers.cpio.CpioArchiveEntry;
import org.apache.commons.compress.archivers.cpio.CpioArchiveInputStream;
import static org.junit.Assert.*;

import java.io.ByteArrayInputStream;
import java.io.IOException;

public class StepDefs {

    private byte[] cpioArchiveData;
    private CpioArchiveInputStream inputStream;
    private CpioArchiveEntry entry;
    private int entryCount;

    @Given("I have a CPIO archive {string} containing an entry with mode {int}")
    public void i_have_a_CPIO_archive_containing_an_entry_with_mode(String filename, Integer mode) throws IOException {
        // Creating a simple CPIO archive with entry that has mode 0x1a4 (octal 0644)
        // This simulates the scenario described where file type bits are zero but permission bits are set

        // Basic CPIO header structure for file with mode 0x1a4
        String headerHex = "303730373031"; // Magic: "070701" hex
        String inode = String.format("%08x", 0);
        String modeHex = String.format("%08x", mode); // This is 0x1a4 (0644 octal)
        String uid = "00000000";
        String gid = "00000000";
        String nlink = String.format("%08x", 1);
        String mtime = "00000000";
        String filesize = "00000000";
        String devmajor = "00000000";
        String devminor = "00000000";
        String rdevmajor = "00000000";
        String rdevminor = "00000000";
        String namesize = String.format("%08x", 6); // Length of filename "test\n"
        String checksum = "00000000";

        StringBuilder archiveBuilder = new StringBuilder();
        archiveBuilder.append(headerHex)
                .append(inode)
                .append(modeHex)
                .append(uid)
                .append(gid)
                .append(nlink)
                .append(mtime)
                .append(filesize)
                .append(devmajor)
                .append(devminor)
                .append(rdevmajor)
                .append(rdevminor)
                .append(namesize)
                .append(checksum)
                .append("7465737400"); // "test\0" in hex

        String archiveHex = archiveBuilder.toString(); 
        cpioArchiveData = new byte[archiveHex.length() / 2];

        for (int i = 0; i < archiveHex.length(); i += 2) {
            cpioArchiveData[i / 2] = (byte) ((Character.digit(archiveHex.charAt(i), 16) << 4)
                    + Character.digit(archiveHex.charAt(i+1), 16));
        }

        inputStream = new CpioArchiveInputStream(new ByteArrayInputStream(cpioArchiveData));
    }

    @When("I attempt to read the entry using CpioArchiveInputStream")
    public void i_attempt_to_read_the_entry_using_CpioArchiveInputStream() throws IOException {
        entryCount = 0;
        entry = inputStream.getNextCPIOEntry();
        if (entry != null) {
            entryCount++;
        }
    }

    @Then("the entry should be returned successfully")
    public void the_entry_should_be_returned_successfully() {
        assertNotNull("Entry should not be null", entry);
    }

    @Then("the entry count should be {int}")
    public void the_entry_count_should_be(Integer expectedCount) {
        assertEquals("Entry count mismatch", expectedCount.intValue(), entryCount);
    }

    // Handle cleanup
    protected void tearDown() {
        if (inputStream != null) {
            try {
                inputStream.close();
            } catch (IOException e) {
                // Log or handle the exception as appropriate
            }
        }
    }
}

